import{_ as o}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o as n,c as r,b as t}from"./chunks/runtime-core.esm-bundler.BcSW7cUG.js";const d=JSON.parse('{"title":"Чувство сопротивления","description":"","frontmatter":{"title":"Чувство сопротивления","date":"2020-09-13T00:00:00.000Z","head":[["link",{"rel":"canonical","href":"https://alterfo.github.io/posts/2020-09-13-resistance"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Чувство сопротивления"}],["meta",{"property":"og:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"property":"og:url","content":"https://alterfo.github.io/posts/2020-09-13-resistance"}],["meta",{"property":"og:image","content":"https://alterfo.github.io/og.png"}],["meta",{"property":"og:site_name","content":"Alterfo"}],["meta",{"property":"og:locale","content":"ru_RU"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Чувство сопротивления"}],["meta",{"name":"twitter:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"name":"twitter:image","content":"https://alterfo.github.io/og.png"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BlogPosting\\",\\"headline\\":\\"Чувство сопротивления\\",\\"description\\":\\"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки.\\",\\"url\\":\\"https://alterfo.github.io/posts/2020-09-13-resistance\\",\\"inLanguage\\":\\"ru-RU\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Oleg Sidorkin\\",\\"alternateName\\":\\"alterfo\\",\\"url\\":\\"https://alterfo.github.io\\",\\"jobTitle\\":\\"Software Engineer\\",\\"knowsAbout\\":[\\"Music\\",\\"Audio DSP\\",\\"AI\\",\\"RAG\\",\\"Frontend Development\\",\\"Solution Architecture\\"],\\"sameAs\\":[\\"https://github.com/alterfo\\"]},\\"datePublished\\":\\"2020-09-13\\"}"]]},"headers":[],"relativePath":"posts/2020-09-13-resistance.md","filePath":"posts/2020-09-13-resistance.md"}'),a={name:"posts/2020-09-13-resistance.md"};function i(s,e,p,l,c,m){return n(),r("div",null,[...e[0]||(e[0]=[t("p",null,"В самом чувстве сопротивления нет ничего хорошего или плохого (привет оценочному суждению). Это механизм защиты от неблагоприятных внешних факторов. Всё ради того чтобы сохранить привычный образ жизни и deal with вторжениями и террором.",-1),t("p",null,'Если человек может сказать "Нет, я против!" это воспринимается нормальным, человек хорошо понимает свои границы и отстаивает свои интересы. Но бывают ситуации, когда неблагоприятные факторы отсутствуют, а сопротивление чувствуется.',-1),t("p",null,"Сопротивление возникает при попытках выбраться из состояния стагнации, гомеостаза, привычного образа жизни. Даже если этот образ жизни деструктивен и наполнен негативными переживаниями. Так уж устроена психика.",-1),t("p",null,'Многим известен принцип психологического айкидо - сначала согласитесь с оппонентом, а потом выскажите свою точку зрения. Но здесь есть пара нюансов - если вы согласны только на словах, оппонент все равно чувствует ваше сопротивление в голосе, интонациях. Второй момент - за психологическим айкидо часто скрывается неумение говорить "нет" когда это действительно нужно.',-1),t("p",null,"В восточных боевых искусствах устойчивость достигается через мягкость. При столкновении тело сначала резко наполняется силой, а потом моментально становится как бы прозрачным. Мягкость обескураживает ожидающего сопротивление противника, как и внезапная техничная резкость. Расслабленную руку гораздо проще убрать из захвата.",-1),t("p",null,"Существуют разные подходы к преодолению сопротивления. Я писал эту статью почти три дня. Очень много чувства сопротивления у меня возникло, болела голова, появлялись более важные дела. Это новая для меня тема, я в ней вообще не разбираюсь, что обо мне скажут знающие люди? Страх оценки, я могу выглядеть глупо. Или страх перед тем, что в результате самоанализа я откопаю что-то страшное. Возникает реальное сопротивление перед воображаемой ситуацией в будущем.",-1),t("p",null,"Все входят в холодную реку по-разному, я - постепенно, а кто-то представляет себя берсерком и идёт напролом. А кто-то вообще не заходит, предпочитая игру в поддавки. А у кого-то холодная река вообще не вызывает сопротивления.",-1)])])}const h=o(a,[["render",i]]);export{d as __pageData,h as default};
